import{_ as e,o as t,c as i,a2 as r}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"Multipart Upload、断点续传、版本、生命周期、CDN 与 ETag","description":"","frontmatter":{"stage":"intermediate","direction":"backend-data","topic":"multipart-version-lifecycle"},"headers":[],"relativePath":"05-backend-data/notes/07-cache-messaging-storage/17-multipart-version-lifecycle-cdn-etag.md","filePath":"05-backend-data/notes/07-cache-messaging-storage/17-multipart-version-lifecycle-cdn-etag.md","lastUpdated":null}'),l={name:"05-backend-data/notes/07-cache-messaging-storage/17-multipart-version-lifecycle-cdn-etag.md"};function o(d,a,p,n,s,c){return t(),i("div",null,[...a[0]||(a[0]=[r(`<h1 id="multipart-upload、断点续传、版本、生命周期、cdn-与-etag" tabindex="-1">Multipart Upload、断点续传、版本、生命周期、CDN 与 ETag <a class="header-anchor" href="#multipart-upload、断点续传、版本、生命周期、cdn-与-etag" aria-label="Permalink to &quot;Multipart Upload、断点续传、版本、生命周期、CDN 与 ETag&quot;">​</a></h1><p>大对象上传需要独立管理 upload ID、part number、校验和和完成清单。S3 ETag 不保证普遍等于对象MD5；版本和生命周期控制恢复与成本，CDN缓存又引入独立失效边界。</p><h2 id="_1-数据流与责任边界" tabindex="-1">1. 数据流与责任边界 <a class="header-anchor" href="#_1-数据流与责任边界" aria-label="Permalink to &quot;1. 数据流与责任边界&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> A[&quot;客户端/生产者&quot;] --&gt; B[&quot;授权与受控元数据&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> B --&gt; C[&quot;对象存储&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> C --&gt; D[&quot;异步处理/验证&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> D --&gt; E[&quot;业务发布与审计&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Multipart Upload 的恢复事实是服务端保存的 upload ID 与 part 清单，发布事实是最终对象版本和 manifest 指针。ETag 在分段上传、加密或不同实现下不一定是内容 MD5，完整性必须使用明确的 checksum；CDN 缓存也不能代替源站版本记录。</p><h2 id="_2-createmultipartupload" tabindex="-1">2. CreateMultipartUpload <a class="header-anchor" href="#_2-createmultipartupload" aria-label="Permalink to &quot;2. CreateMultipartUpload&quot;">​</a></h2><p>机制：初始化metadata/加密并返回uploadId。</p><p>使用：大文件和可恢复上传。</p><p>失败：创建后不完成导致parts收费。</p><p>验证：记录uploadId与业务upload状态。</p><p>取舍：增加请求与状态管理。</p><p>围绕 CreateMultipartUpload 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_3-uploadpart" tabindex="-1">3. UploadPart <a class="header-anchor" href="#_3-uploadpart" aria-label="Permalink to &quot;3. UploadPart&quot;">​</a></h2><p>机制：partNumber标识1..10000，重传同编号覆盖该part。</p><p>使用：并发/断点续传。</p><p>失败：客户端随意声明已完成part。</p><p>验证：ListParts和checksum核对。</p><p>取舍：并发高吞吐但内存/网络峰值。</p><p>围绕 UploadPart 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_4-completemultipartupload" tabindex="-1">4. CompleteMultipartUpload <a class="header-anchor" href="#_4-completemultipartupload" aria-label="Permalink to &quot;4. CompleteMultipartUpload&quot;">​</a></h2><p>机制：提交有序partNumber/ETag清单组合对象。</p><p>使用：全部part验证后原子完成。</p><p>失败：清单错序/缺part或多次竞争完成。</p><p>验证：记录最终version/checksum/size。</p><p>取舍：完成后才形成对象。</p><p>围绕 CompleteMultipartUpload 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_5-abortmultipartupload" tabindex="-1">5. AbortMultipartUpload <a class="header-anchor" href="#_5-abortmultipartupload" aria-label="Permalink to &quot;5. AbortMultipartUpload&quot;">​</a></h2><p>机制：停止并清理未完成parts。</p><p>使用：取消/超时/失败。</p><p>失败：只删业务记录不abort。</p><p>验证：生命周期AbortIncomplete+主动清理。</p><p>取舍：清理最终可能需重试。</p><p>围绕 AbortMultipartUpload 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_6-断点续传状态" tabindex="-1">6. 断点续传状态 <a class="header-anchor" href="#_6-断点续传状态" aria-label="Permalink to &quot;6. 断点续传状态&quot;">​</a></h2><p>机制：服务端保存upload owner、key、part size、expiry、completed parts。</p><p>使用：跨设备/进程恢复。</p><p>失败：信任客户端上传列表。</p><p>验证：从对象存储ListParts对账。</p><p>取舍：可恢复但状态与存储需一致。</p><p>围绕 断点续传状态 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_7-versioning" tabindex="-1">7. Versioning <a class="header-anchor" href="#_7-versioning" aria-label="Permalink to &quot;7. Versioning&quot;">​</a></h2><p>机制：同key写入分配version ID，delete可产生delete marker。</p><p>使用：误覆盖恢复、并发引用固定版本。</p><p>失败：认为普通DELETE永久删除所有版本。</p><p>验证：列版本/恢复演练/权限分离。</p><p>取舍：提高恢复能力与存储成本。</p><p>围绕 Versioning 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_8-lifecycle" tabindex="-1">8. Lifecycle <a class="header-anchor" href="#_8-lifecycle" aria-label="Permalink to &quot;8. Lifecycle&quot;">​</a></h2><p>机制：按prefix/tag/size/age transition/expire/abort。</p><p>使用：成本和保留自动化。</p><p>失败：规则重叠误删或把恢复数据转冷过早。</p><p>验证：policy模拟、inventory、restore演练。</p><p>取舍：自动省钱但执行异步且不可作精确定时器。</p><p>围绕 Lifecycle 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_9-cdn" tabindex="-1">9. CDN <a class="header-anchor" href="#_9-cdn" aria-label="Permalink to &quot;9. CDN&quot;">​</a></h2><p>机制：边缘缓存对象响应，origin与cache key独立。</p><p>使用：公开静态内容和大下载。</p><p>失败：私有对象使用公共cache key。</p><p>验证：签名cookie/URL与cache policy测试。</p><p>取舍：降低源流量但失效/权限复杂。</p><p>围绕 CDN 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_10-etag" tabindex="-1">10. ETag <a class="header-anchor" href="#_10-etag" aria-label="Permalink to &quot;10. ETag&quot;">​</a></h2><p>机制：表示对象特定版本的实体标签，格式依上传和加密。</p><p>使用：条件请求、缓存验证，在限定场景可校验MD5。</p><p>失败：把multipart/SSE-KMS ETag当内容MD5。</p><p>验证：使用明确checksum字段。</p><p>取舍：广泛可用但语义不能泛化。</p><p>围绕 ETag 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_11-条件请求" tabindex="-1">11. 条件请求 <a class="header-anchor" href="#_11-条件请求" aria-label="Permalink to &quot;11. 条件请求&quot;">​</a></h2><p>机制：If-Match/If-None-Match等避免盲覆盖。</p><p>使用：并发写和只创建。</p><p>失败：检查后再PUT存在TOCTOU。</p><p>验证：直接发送条件header并处理412。</p><p>取舍：提升安全但S3兼容实现需核验。</p><p>围绕 条件请求 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_12-方案比较" tabindex="-1">12. 方案比较 <a class="header-anchor" href="#_12-方案比较" aria-label="Permalink to &quot;12. 方案比较&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>收益</th><th>边界</th></tr></thead><tbody><tr><td>单次PUT</td><td>简单</td><td>失败重传整个对象</td></tr><tr><td>Multipart</td><td>并发和续传</td><td>状态、parts成本</td></tr><tr><td>Versioning</td><td>误删恢复</td><td>所有旧版本计费</td></tr><tr><td>内容hash key</td><td>天然不可变CDN</td><td>需要引用切换</td></tr><tr><td>固定key+purge</td><td>URL稳定</td><td>传播延迟与并发覆盖</td></tr></tbody></table><h2 id="_13-完整案例-50gb视频上传" tabindex="-1">13. 完整案例：50GB视频上传 <a class="header-anchor" href="#_13-完整案例-50gb视频上传" aria-label="Permalink to &quot;13. 完整案例：50GB视频上传&quot;">​</a></h2><h3 id="输入与约束" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>浏览器弱网、可续传24小时、每part校验、取消需清理。</p><h3 id="处理步骤" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>API创建业务upload与multipart，选择&gt;=5MiB且part数&lt;=10000。</li><li>按part生成短期预签名，限制owner/key/partNumber/uploadId。</li><li>客户端并发上传并上报checksum，服务端ListParts对账。</li><li>完成时提交有序parts并HEAD最终size/checksum/version。</li><li>失败/取消abort，生命周期7天兜底清理。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>断线只重传缺失parts，完成对象有固定version与校验记录。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>随机中断/重复part/错序清单/取消；未完成parts最终为零。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>只信客户端parts列表会完成混合/缺失对象；完成前必须与服务端存储状态对账。</p><h3 id="恢复要求" tabindex="-1">恢复要求 <a class="header-anchor" href="#恢复要求" aria-label="Permalink to &quot;恢复要求&quot;">​</a></h3><p>断线恢复先用 upload ID 分页执行 <code>ListParts</code>，将服务端 part number、ETag/checksum 与本地清单比较，只重传缺失或校验不符的 part。完成请求必须提交有序清单并以 generation 条件更新一次；过期 generation 不得发布，取消后主动 abort，生命周期只负责兜底回收未完成 parts。</p><h2 id="_14-完整案例-静态资源发布与回滚" tabindex="-1">14. 完整案例：静态资源发布与回滚 <a class="header-anchor" href="#_14-完整案例-静态资源发布与回滚" aria-label="Permalink to &quot;14. 完整案例：静态资源发布与回滚&quot;">​</a></h2><h3 id="输入与约束-1" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束-1" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>Web资源全球CDN，发布后不可出现HTML引用旧/新混合，可快速回滚。</p><h3 id="处理步骤-1" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤-1" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>构建产物用内容hash key并校验checksum。</li><li>先上传全部不可变资源并验证可读。</li><li>最后原子发布manifest/HTML版本指针。</li><li>CDN对hash资源长immutable缓存，HTML短缓存/验证。</li><li>回滚切manifest到旧版本，生命周期延迟清理孤儿。</li></ol><h3 id="输出-1" tabindex="-1">输出 <a class="header-anchor" href="#输出-1" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>新旧资源URL不覆盖，CDN无需大范围purge。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>发布中断时旧manifest仍完整；回滚只切指针；旧资源未过早生命周期删除。</p><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>固定app.js覆盖会让边缘节点混合版本；使用内容寻址key。</p><h3 id="恢复要求-1" tabindex="-1">恢复要求 <a class="header-anchor" href="#恢复要求-1" aria-label="Permalink to &quot;恢复要求&quot;">​</a></h3><p>发布中断时保持旧 manifest 指针不变，已经上传的内容 hash 资源可安全复用。确认新版本全部可从源站读取后再切换指针；回滚只恢复旧 manifest。清理任务从仍被 manifest 引用的版本集合计算保留集，不能按上传时间直接删除旧资源。</p><h2 id="_15-故障注入矩阵" tabindex="-1">15. 故障注入矩阵 <a class="header-anchor" href="#_15-故障注入矩阵" aria-label="Permalink to &quot;15. 故障注入矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>注入</th><th>预期</th><th>禁止</th></tr></thead><tbody><tr><td>签名后撤权</td><td><code>multipart_initiated</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>上传中断</td><td><code>incomplete_bytes</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>同key并发写</td><td><code>part_retries</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>checksum错误</td><td><code>complete_failures</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>扫描器崩溃</td><td><code>abort_failures</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>生命周期延迟</td><td><code>noncurrent_storage</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>对象存储429/503</td><td><code>lifecycle_actions</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>数据库提交后断线</td><td><code>cdn_hit_rate</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr></tbody></table><h2 id="_16-调试与观测" tabindex="-1">16. 调试与观测 <a class="header-anchor" href="#_16-调试与观测" aria-label="Permalink to &quot;16. 调试与观测&quot;">​</a></h2><ol><li><code>multipart_initiated</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>incomplete_bytes</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>part_retries</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>complete_failures</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>abort_failures</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>noncurrent_storage</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>lifecycle_actions</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>cdn_hit_rate</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>origin_bytes</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>checksum_mismatch</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li></ol><p>大文件故障按业务 generation 和 upload ID 检查 <code>ListParts</code> 分页、重复 part、完成清单、最终 object version 与 checksum；静态发布故障再核对 manifest 指针、源站响应、CDN cache key、<code>Age</code> 和命中层级。先区分源站对象错误与边缘陈旧缓存，再决定续传、回滚或失效缓存。</p><h2 id="_17-s3兼容实现边界" tabindex="-1">17. S3兼容实现边界 <a class="header-anchor" href="#_17-s3兼容实现边界" aria-label="Permalink to &quot;17. S3兼容实现边界&quot;">​</a></h2><ol><li>固化最小/最大 part 大小、最大 part 数与最后一段例外，按这些限制计算分段策略。</li><li><code>ListParts</code> 可能分页；续传测试必须覆盖超过单页的上传，不能把首屏结果当完整清单。</li><li>验证重复上传同一 part number 的覆盖规则，以及完成清单对顺序、ETag 和 checksum 的要求。</li><li>明确 <code>CompleteMultipartUpload</code> 超时后的判定方式：先查询最终对象，不能直接创建第二个上传。</li><li>ETag 是否能作为 MD5 取决于分段与加密方式；跨产品校验统一使用显式 checksum。</li><li>测试 versioning 开启后的覆盖、删除、delete marker 和指定 version 读取，保留业务发布的 version ID。</li><li>生命周期规则分别验证未完成 multipart、当前版本和非当前版本；执行是异步的，不能承担同步取消。</li><li>CDN cache key 要明确是否包含 query、Host、压缩协商与选定 headers，避免不同资源误共享缓存。</li><li>对 HTML/manifest 使用短缓存或条件请求，对内容 hash 资源使用 immutable；分别验证 <code>ETag</code>/<code>Last-Modified</code> 行为。</li><li>演练 manifest 切换、边缘缓存未刷新和旧版本回滚，确保生命周期不会删除仍可被回滚指针引用的对象。</li></ol><h2 id="_18-生产检查" tabindex="-1">18. 生产检查 <a class="header-anchor" href="#_18-生产检查" aria-label="Permalink to &quot;18. 生产检查&quot;">​</a></h2><ol><li>part 大小、并发数和最大 part 数由文件大小与产品限制计算，并设客户端内存/带宽上限。</li><li>续传以服务端 <code>ListParts</code> 完整分页结果为准，缺失与 checksum 不符的 part 才重传。</li><li>complete 请求使用有序清单，超时后先 HEAD 最终对象，避免盲目创建第二个 multipart。</li><li>最终对象保存 version 与显式 checksum，不把 multipart ETag 解释为内容 MD5。</li><li>取消路径主动 abort，未完成 multipart 的数量、字节和最老年龄都有告警。</li><li>生命周期分别覆盖未完成上传、非当前版本和孤儿 hash 资源，并验证不会删除回滚依赖。</li><li>静态资源以内容 hash key 不可变发布，HTML/manifest 是唯一可切换发布指针。</li><li>CDN cache key、TTL、条件请求与压缩变体有集成测试，能区分 edge miss 与 origin error。</li><li>发布中断保留旧 manifest；回滚测试证明无需覆盖资源或大范围 purge。</li><li>版本恢复、delete marker、生命周期延迟与 CDN 陈旧缓存纳入定期故障演练。</li></ol><h2 id="_19-综合练习与验收" tabindex="-1">19. 综合练习与验收 <a class="header-anchor" href="#_19-综合练习与验收" aria-label="Permalink to &quot;19. 综合练习与验收&quot;">​</a></h2><p>实现“50GB视频上传”并用“静态资源发布与回滚”验证不同约束。提交状态机、策略、对象清单、失败注入和观测面板。</p><ul><li>[ ] CreateMultipartUpload 的正常、边界、权限和失败路径均通过。</li><li>[ ] UploadPart 的正常、边界、权限和失败路径均通过。</li><li>[ ] CompleteMultipartUpload 的正常、边界、权限和失败路径均通过。</li><li>[ ] AbortMultipartUpload 的正常、边界、权限和失败路径均通过。</li><li>[ ] 断点续传状态 的正常、边界、权限和失败路径均通过。</li><li>[ ] Versioning 的正常、边界、权限和失败路径均通过。</li><li>[ ] Lifecycle 的正常、边界、权限和失败路径均通过。</li><li>[ ] CDN 的正常、边界、权限和失败路径均通过。</li><li>[ ] 两个完整案例都可在隔离环境重复运行。</li><li>[ ] 对象存储故障不改变数据库业务不变量。</li><li>[ ] 所有孤儿、版本、parts和审计记录有保留/清理策略。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://docs.aws.amazon.com/AmazonS3/latest/userguide/mpuoverview.html" target="_blank" rel="noreferrer">AWS S3 multipart upload</a>（访问日期：2026-07-17）</li><li><a href="https://docs.aws.amazon.com/AmazonS3/latest/userguide/Versioning.html" target="_blank" rel="noreferrer">AWS S3 Versioning</a>（访问日期：2026-07-17）</li><li><a href="https://docs.aws.amazon.com/AmazonS3/latest/userguide/lifecycle-configuration-examples.html" target="_blank" rel="noreferrer">AWS S3 Lifecycle examples</a>（访问日期：2026-07-17）</li><li><a href="https://docs.aws.amazon.com/AmazonS3/latest/userguide/UsingMetadata.html" target="_blank" rel="noreferrer">AWS S3 object metadata and ETag</a>（访问日期：2026-07-17）</li><li><a href="https://www.rfc-editor.org/rfc/rfc9110.html#name-etag" target="_blank" rel="noreferrer">RFC 9110 entity tags</a>（访问日期：2026-07-17）</li></ul>`,117)])])}const m=e(l,[["render",o]]);export{u as __pageData,m as default};
